+    [Test]
+    [HandlerFunctions('ItemTrackingPageHandler,ItemTrackingSummaryPageHandler,GetShipmentLinesPageHandler')]
+    [Scope('OnPrem')]
+    procedure ItemTrackingPreservedOnSalesInvoiceQtyChangeAfterGetShipmentLines()
+    var
+        Customer: Record Customer;
+        Item: Record Item;
+        ItemJournalLine: Record "Item Journal Line";
+        SalesHeaderOrder: Record "Sales Header";
+        SalesHeaderInvoice: Record "Sales Header";
+        SalesLineOrder: Record "Sales Line";
+        SalesLineInvoice: Record "Sales Line";
+        ReservationEntry: Record "Reservation Entry";
+        Quantity: Decimal;
+    begin
+        // [FEATURE] [AI test]
+        // [SCENARIO 579483] Item tracking lines are preserved when quantity is reduced on Sales Invoice line created via Get Shipment Lines for item with Reserve Always.
+        Initialize();
+
+        // [GIVEN] Item "I" with Lot Tracking Code, Reserve = Always, and Costing Method = FIFO.
+        LibrarySales.CreateCustomer(Customer);
+        CreateItem(Item, ItemTrackingCodeLotSpecific.Code, Item."Costing Method"::FIFO);
+        Item.Validate(Reserve, Item.Reserve::Always);
+        Item.Modify(true);
+
+        // [GIVEN] Posted positive adjustment with Lot Item Tracking for Item "I".
+        Quantity := LibraryRandom.RandIntInRange(3, 10);
+        CreateAndPostItemJournalLine(
+          ItemJournalLine."Entry Type"::"Positive Adjmt.", Item."No.", LocationBlue.Code,
+          Quantity, 0, false, AssignTracking::LotNo);
+
+        // [GIVEN] Shipped Sales Order "SO" with Lot Item Tracking for Item "I".
+        CreateAndPostSalesOrderWithTracking(
+          SalesHeaderOrder, SalesLineOrder, Customer."No.", Item."No.", LocationBlue.Code, Quantity);
+
+        // [GIVEN] Sales Invoice "SI" with lines copied from Sales Shipment by Get Shipment Lines function.
+        LibrarySales.CreateSalesHeader(SalesHeaderInvoice, SalesHeaderInvoice."Document Type"::Invoice, Customer."No.");
+        SalesLineInvoice."Document Type" := SalesHeaderInvoice."Document Type";
+        SalesLineInvoice."Document No." := SalesHeaderInvoice."No.";
+        LibrarySales.GetShipmentLines(SalesLineInvoice);
+
+        // [WHEN] Reduce quantity on the Sales Invoice line.
+        SalesLineInvoice.SetRange("Document Type", SalesHeaderInvoice."Document Type");
+        SalesLineInvoice.SetRange("Document No.", SalesHeaderInvoice."No.");
+        SalesLineInvoice.SetRange(Type, SalesLineInvoice.Type::Item);
+        SalesLineInvoice.FindFirst();
+        SalesLineInvoice.Validate(Quantity, Quantity - 1);
+        SalesLineInvoice.Modify(true);
+
+        // [THEN] Item tracking lines (Reservation Entries) still exist for the Sales Invoice.
+        ReservationEntry.SetRange("Source Type", Database::"Sales Line");
+        ReservationEntry.SetRange("Source Subtype", SalesHeaderInvoice."Document Type"::Invoice.AsInteger());
+        ReservationEntry.SetRange("Source ID", SalesHeaderInvoice."No.");
+        Assert.RecordIsNotEmpty(ReservationEntry);
+    end;
+
     local procedure Initialize()
     var
         LibraryERMCountryData: Codeunit "Library - ERM Country Data";
"

