+    begin
+        ProdOrderRoutingLine.SetRange(Status, Status);
+        ProdOrderRoutingLine.SetRange("Prod. Order No.", ProductionOrderNo);
+        ProdOrderRoutingLine.FindSet();
+        repeat
+            Assert.AreEqual(ExpectedInputQty, ProdOrderRoutingLine."Input Quantity", 'Input Quantity should be recalculated to remaining quantity after replan');
+        until ProdOrderRoutingLine.Next() = 0;
+    end;
