+    [Test]
+    [Scope('OnPrem')]
+    procedure OverpickQtyChangeOnLastTakeLineUpdatesCorrespondingPlaceLine()
+    var
+        Bin: array[5] of Record Bin;
+        Item: array[2] of Record Item;
+        Location: Record Location;
+        ProductionOrder: Record "Production Order";
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ProdOrderComponent: Record "Prod. Order Component";
+        TakeWarehouseActivityLine: Record "Warehouse Activity Line";
+        PlaceWarehouseActivityLine: Record "Warehouse Activity Line";
+        FirstPlaceWarehouseActivityLine: Record "Warehouse Activity Line";
+        OriginalQuantity: Decimal;
+        NewQuantity: Decimal;
+    begin
+        // [FEATURE] [AI test]
+        // [SCENARIO 543210] Changing quantity on last Take line in Warehouse Pick updates the corresponding Place line, not the first Place line
+        Initialize();
+
+        // [GIVEN] Location "L" with Require Pick and Prod. Consump. Whse. Handling = Warehouse Pick (mandatory)
+        LibraryWarehouse.CreateLocationWMS(Location, true, false, true, false, true);
+        Location.Validate("Prod. Consump. Whse. Handling", Location."Prod. Consump. Whse. Handling"::"Warehouse Pick (mandatory)");
+        Location.Modify(true);
+
+        // [GIVEN] Five Bins: three storage Bins "B1","B2","B3", From-Production Bin "B4", To-Production Bin "B5"
+        LibraryWarehouse.CreateBin(Bin[1], Location.Code, Bin[1].Code, '', '');
+        LibraryWarehouse.CreateBin(Bin[2], Location.Code, Bin[2].Code, '', '');
+        LibraryWarehouse.CreateBin(Bin[3], Location.Code, Bin[3].Code, '', '');
+        LibraryWarehouse.CreateBin(Bin[4], Location.Code, Bin[4].Code, '', '');
+        LibraryWarehouse.CreateBin(Bin[5], Location.Code, Bin[5].Code, '', '');
+        Location.Validate("From-Production Bin Code", Bin[4].Code);
+        Location.Validate("To-Production Bin Code", Bin[5].Code);
+        Location.Modify(true);
+
+        // [GIVEN] Component Item "CI" with Allow Whse. Overpick enabled
+        OriginalQuantity := 100;
+        LibraryInventory.CreateItem(Item[1]);
+        Item[1].Validate("Allow Whse. Overpick", true);
+        Item[1].Modify(true);
+
+        // [GIVEN] 100 qty of "CI" posted to each of three Bins "B1","B2","B3"
+        CreateAndPostItemJournalLine(Item[1]."No.", OriginalQuantity, Bin[1].Code, Location.Code, false);
+        CreateAndPostItemJournalLine(Item[1]."No.", OriginalQuantity, Bin[2].Code, Location.Code, false);
+        CreateAndPostItemJournalLine(Item[1]."No.", OriginalQuantity, Bin[3].Code, Location.Code, false);
+
+        // [GIVEN] Production BOM with "CI" as component, Quantity per = 1
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, Item[1]."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, Item[1]."No.", 1);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        // [GIVEN] Manufactured Item "MI" with Production BOM
+        LibraryInventory.CreateItem(Item[2]);
+        Item[2].Validate("Replenishment System", Item[2]."Replenishment System"::"Prod. Order");
+        Item[2].Validate("Production BOM No.", ProductionBOMHeader."No.");
+        Item[2].Modify(true);
+
+        // [GIVEN] Released Production Order for 300 qty of "MI" at Location "L"
+        CreateAndRefreshProductionOrder(
+            ProductionOrder, ProductionOrder.Status::Released, Item[2]."No.", 300, Location.Code, Bin[5].Code);
+
+        // [GIVEN] Prod. Order Component for "CI" with Bin Code = From-Production Bin "B4"
+        ProdOrderComponent.SetRange("Item No.", Item[1]."No.");
+        ProdOrderComponent.FindFirst();
+        ProdOrderComponent.Validate("Bin Code", Bin[4].Code);
+        ProdOrderComponent.Modify(true);
+
+        // [GIVEN] Warehouse Pick created from Production Order with multiple Take/Place line pairs
+        LibraryWarehouse.CreateWhsePickFromProduction(ProductionOrder);
+
+        // [GIVEN] Find the last Take line in the Warehouse Pick
+        TakeWarehouseActivityLine.SetRange("Item No.", Item[1]."No.");
+        TakeWarehouseActivityLine.SetRange("Action Type", TakeWarehouseActivityLine."Action Type"::Take);
+        TakeWarehouseActivityLine.FindLast();
+        NewQuantity := 50;
+
+        // [WHEN] Quantity on last Take line is changed from 100 to 50
+        TakeWarehouseActivityLine.Validate(Quantity, NewQuantity);
+        TakeWarehouseActivityLine.Modify(true);
+
+        // [THEN] The Place line corresponding to the last Take line has Quantity = 50
+        PlaceWarehouseActivityLine.SetRange("Activity Type", TakeWarehouseActivityLine."Activity Type");
+        PlaceWarehouseActivityLine.SetRange("No.", TakeWarehouseActivityLine."No.");
+        PlaceWarehouseActivityLine.SetRange("Action Type", PlaceWarehouseActivityLine."Action Type"::Place);
+        PlaceWarehouseActivityLine.SetFilter("Line No.", '>%1', TakeWarehouseActivityLine."Line No.");
+        PlaceWarehouseActivityLine.FindFirst();
+        Assert.AreEqual(
+            NewQuantity,
+            PlaceWarehouseActivityLine.Quantity,
+            StrSubstNo(
+                QuantityErr,
+                PlaceWarehouseActivityLine.FieldCaption(Quantity),
+                NewQuantity,
+                PlaceWarehouseActivityLine.TableCaption()));
+
+        // [THEN] The first Place line still has the original Quantity = 100
+        FirstPlaceWarehouseActivityLine.SetRange("Activity Type", TakeWarehouseActivityLine."Activity Type");
+        FirstPlaceWarehouseActivityLine.SetRange("No.", TakeWarehouseActivityLine."No.");
+        FirstPlaceWarehouseActivityLine.SetRange("Action Type", FirstPlaceWarehouseActivityLine."Action Type"::Place);
+        FirstPlaceWarehouseActivityLine.FindFirst();
+        Assert.AreEqual(
+            OriginalQuantity,
+            FirstPlaceWarehouseActivityLine.Quantity,
+            StrSubstNo(
+                QuantityErr,
+                FirstPlaceWarehouseActivityLine.FieldCaption(Quantity),
+                OriginalQuantity,
+                FirstPlaceWarehouseActivityLine.TableCaption()));
+    end;
+
     local procedure Initialize()
     var
         LibraryERMCountryData: Codeunit "Library - ERM Country Data";
"

