+        // [FEATURE] [AI test]
+        // [SCENARIO 604208] Changing item no. in manual contract line disconnects old subscription line from contract
+        Initialize();
+
+        // [GIVEN] Customer Subscription Contract "CSC" with manually created contract line "CL" for Item "I1"
+        ContractTestLibrary.CreateCustomer(Customer);
+        ContractTestLibrary.CreateCustomerContract(CustomerContract, Customer."No.");
+        ContractTestLibrary.InsertCustomerContractItemLine(CustomerContract, CustomerContractLine);
+        OldSubscriptionLineEntryNo := CustomerContractLine."Subscription Line Entry No.";
+
+        // [GIVEN] A second Item "I2" with Subscription Option = Service Commitment Item
+        ContractTestLibrary.CreateItemWithServiceCommitmentOption(Item2, Enum::"Item Service Commitment Type"::"Service Commitment Item");
+
+        // [WHEN] Change Item No. on contract line "CL" from "I1" to "I2"
+        CustomerContractLine.Validate("No.", Item2."No.");
+        CustomerContractLine.Modify(false);
+
+        // [THEN] The old Subscription Line for "I1" is disconnected from contract "CSC"
+        OldSubscriptionLine.Get(OldSubscriptionLineEntryNo);
+        Assert.AreEqual('', OldSubscriptionLine."Subscription Contract No.", 'Old Subscription Line should be disconnected from contract');
+        Assert.AreEqual(0, OldSubscriptionLine."Subscription Contract Line No.", 'Old Subscription Line contract line no. should be cleared');
+    end;
+
     #endregion Tests

     #region Procedures
"

