+    [Test]
+    [HandlerFunctions('JobTransferToSalesInvoiceRequestPageHandler,MessageHandler')]
+    procedure CombineJobTasksWithSameSellToBillToIntoOneSalesInvoiceForMultipleCustomers()
+    var
+        Job: Record Job;
+        JobPlanningLine: Record "Job Planning Line";
+        Customer: Record Customer;
+        JobTasks: array[2] of Record "Job Task";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        Qty: Decimal;
+    begin
+        // [FEATURE] [AI test]
+        // [SCENARIO 567890] Two job tasks "JT1" and "JT2" with same Sell-to, Bill-to, and Invoice Currency are combined into one Sales Invoice for Multiple Customers billing
+        Initialize();
+
+        // [GIVEN] Set Multiple Customers on Project Setup
+        SetMultiupleCustomersOnProjectSetup();
+
+        // [GIVEN] Create Customer "C"
+        LibrarySales.CreateCustomer(Customer);
+
+        // [GIVEN] Create new Project with Customer "C"
+        LibraryJob.CreateJob(Job, Customer."No.");
+
+        // [GIVEN] Create Project Task "JT1" with Sell-to "C" and Bill-to "C"
+        LibraryJob.CreateJobTask(Job, JobTasks[1]);
+
+        // [GIVEN] Create Project Task "JT2" with Sell-to "C" and Bill-to "C"
+        LibraryJob.CreateJobTask(Job, JobTasks[2]);
+
+        // [GIVEN] Create Job Planning Lines with Qty to Transfer to Invoice for "JT1" and "JT2"
+        Qty := LibraryRandom.RandInt(10);
+        CreateJobPlanningLineWithQtyToTransferToInvoice(JobPlanningLine, JobTasks[1], Qty, Qty);
+        CreateJobPlanningLineWithQtyToTransferToInvoice(JobPlanningLine, JobTasks[2], Qty, Qty);
+        Commit();
+
+        // [GIVEN] Filter Job Planning Lines by Project
+        JobPlanningLine.Reset();
+        JobPlanningLine.SetFilter("Job No.", '%1', Job."No.");
+        JobPlanningLine.FindSet();
+
+        // [GIVEN] Enqueue data for Message Handler
+        LibraryVariableStorage.Enqueue(LinesTransferedToInvoiceMsg);
+
+        // [WHEN] Create Sales Invoices
+        JobCreateInvoice.CreateSalesInvoice(JobPlanningLine, false);
+
+        // [THEN] Only one Sales Invoice is created for Customer "C"
+        SalesHeader.SetRange("Document Type", SalesHeader."Document Type"::Invoice);
+        SalesHeader.SetRange("Sell-to Customer No.", Customer."No.");
+        SalesHeader.SetRange("Bill-to Customer No.", Customer."No.");
+        Assert.AreEqual(1, SalesHeader.Count(), 'Expected one Sales Invoice for tasks with same Sell-to and Bill-to');
+
+        // [THEN] Sales Invoice contains lines from both Project Tasks
+        SalesHeader.FindFirst();
+        SalesLine.SetRange("Document Type", SalesHeader."Document Type");
+        SalesLine.SetRange("Document No.", SalesHeader."No.");
+        SalesLine.SetRange("Job No.", Job."No.");
+        Assert.AreEqual(2, SalesLine.Count(), 'Expected two Sales Lines from both Project Tasks');
+    end;
+
     local procedure Initialize()
     begin
         LibraryTestInitialize.OnTestInitialize(Codeunit::"Jobs - Multiple Customers");
"

