"diff --git a/App/Apps/W1/Shopify/test/Invoicing/ShpfyCopyDocumentTest.Codeunit.al b/App/Apps/W1/Shopify/test/Invoicing/ShpfyCopyDocumentTest.Codeunit.al
new file mode 100644
index 00000000..a5f33b20
--- /dev/null
+++ b/App/Apps/W1/Shopify/test/Invoicing/ShpfyCopyDocumentTest.Codeunit.al
@@ -0,0 +1,88 @@
+codeunit 139614 "Shpfy Copy Document Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        Any: Codeunit Any;
+        LibraryAssert: Codeunit "Library Assert";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        IsInitialized: Boolean;
+
+    [Test]
+    procedure CopyPostedInvoiceClearsShopifyFields()
+    var
+        Item: Record Item;
+        Customer: Record Customer;
+        SalesHeader: Record "Sales Header";
+        CopyDocumentMgt: Codeunit "Copy Document Mgt.";
+        PostedInvoiceNo: Code[20];
+        OrderId: BigInteger;
+        OrderNo: Code[50];
+        RefundId: BigInteger;
+    begin
+        // [FEATURE] [AI test]
+        // [SCENARIO 123456] Copying posted sales invoice clears Shopify Order Id, Order No., and Refund Id
+        Initialize();
+
+        // [GIVEN] Item "I" with unit price
+        OrderId := Any.IntegerInRange(10000, 99999);
+        OrderNo := CopyStr(Format(Any.IntegerInRange(1000, 9999)), 1, 50);
+        RefundId := Any.IntegerInRange(10000, 99999);
+        CreateItem(Item, Any.IntegerInRange(100, 999));
+        LibrarySales.CreateCustomer(Customer);
+
+        // [GIVEN] Posted sales invoice "SI" with Shopify fields populated
+        PostedInvoiceNo := CreateAndPostSalesInvoiceWithShopifyFields(Item, Customer, OrderId, OrderNo, RefundId);
+
+        // [GIVEN] New sales invoice "I"
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, Customer."No.");
+
+        // [WHEN] Copy Document is run from posted invoice "SI" to new invoice "I"
+        CopyDocumentMgt.SetProperties(true, false, false, false, true, false, false);
+        CopyDocumentMgt.CopySalesDoc("Sales Document Type From"::"Posted Invoice", PostedInvoiceNo, SalesHeader);
+
+        // [THEN] Shopify Order Id is cleared on the new invoice
+        SalesHeader.Get(SalesHeader."Document Type", SalesHeader."No.");
+        LibraryAssert.AreEqual(0, SalesHeader."Shpfy Order Id", 'Shpfy Order Id should be cleared after copy');
+
+        // [THEN] Shopify Order No. is cleared on the new invoice
+        LibraryAssert.AreEqual('', SalesHeader."Shpfy Order No.", 'Shpfy Order No. should be cleared after copy');
+
+        // [THEN] Shopify Refund Id is cleared on the new invoice
+        LibraryAssert.AreEqual(0, SalesHeader."Shpfy Refund Id", 'Shpfy Refund Id should be cleared after copy');
+    end;
+
+    local procedure Initialize()
+    begin
+        if IsInitialized then
+            exit;
+        IsInitialized := true;
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+    end;
+
+    local procedure CreateItem(var Item: Record Item; Amount: Decimal)
+    begin
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Unit Price", Amount);
+        Item.Validate("Last Direct Cost", Amount);
+        Item.Modify(true);
+    end;
+
+    local procedure CreateAndPostSalesInvoiceWithShopifyFields(Item: Record Item; Customer: Record Customer; OrderId: BigInteger; OrderNo: Code[50]; RefundId: BigInteger): Code[20]
+    var
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+    begin
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, Customer."No.");
+        SalesHeader."Shpfy Order Id" := OrderId;
+        SalesHeader."Shpfy Order No." := OrderNo;
+        SalesHeader."Shpfy Refund Id" := RefundId;
+        SalesHeader.Modify();
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", 1);
+        exit(LibrarySales.PostSalesDocument(SalesHeader, true, true));
+    end;
+}
"

