@@ -5248,6 +5248,66 @@ codeunit 137079 "SCM Production Order III"
         VerifyProdOrderCapacity(ProductionOrder, WorkCenters[3], 1);
     end;

+    [Test]
+    [HandlerFunctions('ItemTrackingHandler')]
+    [Scope('OnPrem')]
+    procedure PostConsumptionReservedToMultipleLotTrackedILEs()
+    var
+        CompItem: Record Item;
+        ParentItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionOrder: Record "Production Order";
+        ProdOrderLine: Record "Prod. Order Line";
+        ItemJournalLine: Record "Item Journal Line";
+        ItemLedgerEntry: Record "Item Ledger Entry";
+        LotNo: Code[50];
+        TotalQty: Decimal;
+    begin
+        // [FEATURE] [AI test]
+        // [SCENARIO 546497] Post consumption reserved to multiple lot tracked Item Ledger Entries should succeed
+        Initialize();
+
+        // [GIVEN] Lot-tracked component Item "CI" with Reserve = Always
+        CreateItemWithItemTrackingCode(CompItem);
+        CompItem.Validate(Reserve, CompItem.Reserve::Always);
+        CompItem.Validate("Flushing Method", CompItem."Flushing Method"::Manual);
+        CompItem.Modify(true);
+
+        // [GIVEN] Parent Item "PI" with production BOM that consumes "CI"
+        CreateCertifiedProductionBOM(ProductionBOMHeader, CompItem, 1);
+        CreateProductionItem(ParentItem, ProductionBOMHeader."No.");
+
+        // [GIVEN] 3 positive adjustments for "CI" with same Lot "L" for quantities 5, 10, 20
+        LotNo := LibraryUtility.GenerateGUID();
+        TotalQty := 35;
+        CreateAndPostInvtAdjustmentOfItemWithLot(CompItem."No.", LotNo, 5);
+        CreateAndPostInvtAdjustmentOfItemWithLot(CompItem."No.", LotNo, 10);
+        CreateAndPostInvtAdjustmentOfItemWithLot(CompItem."No.", LotNo, 20);
+
+        // [GIVEN] Released Production Order for "PI" for 35 qty, refreshed (auto-reserves to 3 ILEs)
+        CreateAndRefreshReleasedProductionOrder(ProductionOrder, ParentItem."No.", TotalQty, '', '');
+
+        // [WHEN] Post consumption journal for "CI" with Lot "L" for 35 qty
+        LibraryInventory.ClearItemJournal(ConsumptionItemJournalTemplate, ConsumptionItemJournalBatch);
+        LibraryInventory.CreateItemJournalLine(
+          ItemJournalLine, ConsumptionItemJournalTemplate.Name, ConsumptionItemJournalBatch.Name,
+          ItemJournalLine."Entry Type"::Consumption, CompItem."No.", TotalQty);
+        ItemJournalLine.Validate("Order No.", ProductionOrder."No.");
+        FindProdOrderLine(ProdOrderLine, ProductionOrder.Status, ProductionOrder."No.");
+        ItemJournalLine.Validate("Order Line No.", ProdOrderLine."Line No.");
+        ItemJournalLine.Modify(true);
+        OpenItemTrackingLinesSetValue(ItemJournalLine, LotNo, '', TotalQty);
+        LibraryInventory.PostItemJournalLine(ConsumptionItemJournalTemplate.Name, ConsumptionItemJournalBatch.Name);
+
+        // [THEN] Consumption entries are posted for total quantity 35
+        ItemLedgerEntry.SetRange("Item No.", CompItem."No.");
+        ItemLedgerEntry.SetRange("Entry Type", ItemLedgerEntry."Entry Type"::Consumption);
+        ItemLedgerEntry.CalcSums(Quantity);
+        Assert.AreEqual(-TotalQty, ItemLedgerEntry.Quantity, 'Total consumption quantity should match');
+
+        LibraryVariableStorage.AssertEmpty();
+    end;
+
     local procedure Initialize()
     begin
         LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Production Order III");
"

