     end;

+    [Test]
+    [Scope('OnPrem')]
+    procedure NonDeductibleVATAmountInVATEntryAfterPostingFullVATFromJournal()
+    var
+        VATPostingSetup: Record "VAT Posting Setup";
+        GenJournalLine: Record "Gen. Journal Line";
+        GLAccount: Record "G/L Account";
+        VATEntry: Record "VAT Entry";
+        NonDeductibleVATPct: Decimal;
+    begin
+        // [FEATURE] [AI test]
+        // [SCENARIO 565432] Non-Deductible VAT Amount is correct in VAT Entry when posting Full VAT journal line with Non-Deductible VAT
+        Initialize();
+
+        // [GIVEN] VAT Posting Setup "VS" with "VAT Calculation Type" = "Full VAT", "Non-Deductible VAT %" = "X"
+        NonDeductibleVATPct := LibraryRandom.RandIntInRange(10, 90);
+        LibraryERM.CreateVATPostingSetupWithAccounts(VATPostingSetup, VATPostingSetup."VAT Calculation Type"::"Full VAT", LibraryRandom.RandIntInRange(10, 25));
+        LibraryNonDeductibleVAT.SetAllowNonDeductibleVATForVATPostingSetup(VATPostingSetup);
+        VATPostingSetup.Validate("Non-Deductible VAT %", NonDeductibleVATPct);
+        VATPostingSetup.Validate("Non-Ded. Purchase VAT Account", LibraryERM.CreateGLAccountNo());
+        VATPostingSetup.Modify(true);
+
+        // [GIVEN] General journal line "GJL" with Full VAT and Non-Deductible VAT Setup
+        LibraryJournals.CreateGenJournalLineWithBatch(
+            GenJournalLine, GenJournalLine."Document Type"::" ", GenJournalLine."Account Type"::"G/L Account",
+            LibraryERM.CreateGLAccountWithVATPostingSetup(VATPostingSetup, GLAccount."Gen. Posting Type"::Purchase), LibraryRandom.RandIntInRange(100, 1000));
+
+        // [WHEN] Post general journal line
+        LibraryERM.PostGeneralJnlLine(GenJournalLine);
+
+        // [THEN] VAT Entry "VE" has "Non-Deductible VAT Amount" = Round("GJL".Amount * "X" / 100)
+        VATEntry.SetRange("Posting Date", GenJournalLine."Posting Date");
+        VATEntry.SetRange("Document No.", GenJournalLine."Document No.");
+        VATEntry.FindFirst();
+        Assert.AreEqual(
+            Round(GenJournalLine.Amount * NonDeductibleVATPct / 100),
+            VATEntry."Non-Deductible VAT Amount",
+            'Non-Deductible VAT Amount should be calculated for Full VAT');
+    end;
+
     local procedure Initialize()
     var
         LibraryERMCountryData: Codeunit "Library - ERM Country Data";
"

