+    [Test]
+    [Scope('OnPrem')]
+    procedure IssuedReminderCustLedgEntryDimFromModifiedHeader()
+    var
+        ReminderLevel: Record "Reminder Level";
+        SalesHeader: Record "Sales Header";
+        Customer: Record Customer;
+        ReminderHeader: Record "Reminder Header";
+        ReminderTerms: Record "Reminder Terms";
+        CustLedgerEntry: Record "Cust. Ledger Entry";
+        GLEntry: Record "G/L Entry";
+        CustomerPostingGroup: Record "Customer Posting Group";
+        DimensionValue: array[2] of Record "Dimension Value";
+        DefaultDimension: Record "Default Dimension";
+        GeneralLedgerSetup: Record "General Ledger Setup";
+        IssuedReminderNo: Code[20];
+        GlobalDim1Code: Code[20];
+    begin
+        // [FEATURE] [AI test]
+        // [SCENARIO 568432] Customer Ledger Entry and G/L Entry should have updated dimension when Reminder Header dimension is modified before issuing
+        Initialize();
+
+        // [GIVEN] Two Dimension Values "DV1" and "DV2" for Global Dimension 1
+        GeneralLedgerSetup.Get();
+        GlobalDim1Code := GeneralLedgerSetup."Global Dimension 1 Code";
+        LibraryDimension.CreateDimensionValue(DimensionValue[1], GlobalDim1Code);
+        LibraryDimension.CreateDimensionValue(DimensionValue[2], GlobalDim1Code);
+
+        // [GIVEN] Customer "C" with Reminder Terms and Post Additional Fee = True
+        CreateReminderTerms(ReminderLevel, '');
+        ReminderTerms.Get(ReminderLevel."Reminder Terms Code");
+        ReminderTerms."Post Additional Fee" := true;
+        ReminderTerms.Modify(true);
+        Customer.Get(CreateCustomer(ReminderLevel."Reminder Terms Code", ''));
+        CustomerPostingGroup.Get(Customer."Customer Posting Group");
+
+        // [GIVEN] Customer "C" has Default Dimension for Global Dimension 1 = "DV1"
+        LibraryDimension.CreateDefaultDimension(
+            DefaultDimension, DATABASE::Customer, Customer."No.",
+            GlobalDim1Code, DimensionValue[1].Code);
+
+        // [GIVEN] Posted Sales Invoice for Customer "C"
+        CreateAndPostSalesInvoice(SalesHeader, Customer."No.");
+
+        // [GIVEN] Suggested Reminder for Customer "C" with Additional Fee line
+        ReminderHeader.Get(
+            CreateAndSuggestReminder(
+                SalesHeader."Sell-to Customer No.",
+                CalcDate('<1D>', CalcDate(ReminderLevel."Grace Period", SalesHeader."Due Date"))));
+
+        // [GIVEN] Reminder Header Global Dimension 1 is changed to "DV2"
+        ReminderHeader.Validate("Shortcut Dimension 1 Code", DimensionValue[2].Code);
+        ReminderHeader.Modify(true);
+
+        // [WHEN] Reminder is issued
+        IssuedReminderNo := IssueReminderAndGetIssuedNo(ReminderHeader."No.");
+
+        // [THEN] Customer Ledger Entry for the Reminder has Global Dimension 1 Code = "DV2"
+        CustLedgerEntry.SetRange("Document Type", CustLedgerEntry."Document Type"::Reminder);
+        CustLedgerEntry.SetRange("Document No.", IssuedReminderNo);
+        CustLedgerEntry.FindFirst();
+        Assert.AreEqual(
+            DimensionValue[2].Code, CustLedgerEntry."Global Dimension 1 Code",
+            'Customer Ledger Entry should have the updated dimension from the Reminder Header');
+
+        // [THEN] G/L Entry for Additional Fee Account has Global Dimension 1 Code = "DV2"
+        GLEntry.SetRange("Document Type", GLEntry."Document Type"::Reminder);
+        GLEntry.SetRange("Document No.", IssuedReminderNo);
+        GLEntry.SetRange("G/L Account No.", CustomerPostingGroup."Additional Fee Account");
+        GLEntry.FindFirst();
+        Assert.AreEqual(
+            DimensionValue[2].Code, GLEntry."Global Dimension 1 Code",
+            'G/L Entry should have the updated dimension from the Reminder Header');
+    end;
