+    [Test]
+    [Scope('OnPrem')]
+    procedure ExtTextOnMultiItemsBlanketOrderCarriedToSalesOrder()
+    var
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        SalesOrderLine: Record "Sales Line";
+        Item: array[3] of Record Item;
+        ExtendedTextHeader: Record "Extended Text Header";
+        ExtendedTextLine: Record "Extended Text Line";
+        TransferExtendedText: Codeunit "Transfer Extended Text";
+        SalesOrderNo: Code[20];
+        i: Integer;
+    begin
+        // [FEATURE] [AI test]
+        // [SCENARIO 563457] All extended text lines are carried to Sales Order when Make Order from Blanket Sales Order with multiple items
+        Initialize();
+
+        // [GIVEN] Three items "I1", "I2", "I3" each with extended text enabled for Blanket Order
+        for i := 1 to 3 do begin
+            LibraryInventory.CreateItem(Item[i]);
+            Item[i].Validate("Automatic Ext. Texts", true);
+            Item[i].Modify(true);
+            LibraryInventory.CreateExtendedTextHeaderItem(ExtendedTextHeader, Item[i]."No.");
+            ExtendedTextHeader.Validate("Sales Blanket Order", true);
+            ExtendedTextHeader.Modify(true);
+            LibraryInventory.CreateExtendedTextLineItem(ExtendedTextLine, ExtendedTextHeader);
+        end;
+
+        // [GIVEN] Blanket Sales Order "BSO" with lines for "I1", "I2", "I3" and extended text inserted
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::"Blanket Order", LibrarySales.CreateCustomerNo());
+        for i := 1 to 3 do begin
+            LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item[i]."No.", LibraryRandom.RandIntInRange(1, 10));
+            if TransferExtendedText.SalesCheckIfAnyExtText(SalesLine, false) then
+                TransferExtendedText.InsertSalesExtText(SalesLine);
+        end;
+
+        // [WHEN] Make Order from Blanket Sales Order "BSO"
+        SalesOrderNo := LibrarySales.BlanketSalesOrderMakeOrder(SalesHeader);
+
+        // [THEN] All three extended text lines are present on the Sales Order
+        SalesOrderLine.SetRange("Document Type", SalesOrderLine."Document Type"::Order);
+        SalesOrderLine.SetRange("Document No.", SalesOrderNo);
+        SalesOrderLine.SetRange(Type, SalesOrderLine.Type::" ");
+        SalesOrderLine.SetFilter("Attached to Line No.", '<>0');
+        Assert.AreEqual(3, SalesOrderLine.Count, 'All extended text lines should be carried to the Sales Order');
+    end;
+
     local procedure Initialize()
     var
         LibraryERMCountryData: Codeunit "Library - ERM Country Data";
"

