+namespace Microsoft.Assembly.Test;
+
+using Microsoft.Assembly.Document;
+using Microsoft.Assembly.Setup;
+using Microsoft.Inventory.Item;
+
+codeunit 137933 "SCM Asm. Line Show Document"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Assembly] [SCM]
+    end;
+
+    var
+        LibraryAssembly: Codeunit "Library - Assembly";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        IsInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('BlanketAssemblyOrderPageHandler')]
+    [Scope('OnPrem')]
+    procedure ShowDocumentOpensBlanketAssemblyOrderForBlanketLine()
+    var
+        AssemblyHeader: Record "Assembly Header";
+        AssemblyLine: Record "Assembly Line";
+        AssemblyLines: TestPage "Assembly Lines";
+    begin
+        // [FEATURE] [AI test]
+        // [SCENARIO 565432] Show Document on Assembly Lines page opens Blanket Assembly Order page for blanket order lines
+        Initialize();
+
+        // [GIVEN] A blanket assembly order "BAO" with an assembly line "AL"
+        CreateBlanketAssemblyOrder(AssemblyHeader);
+        FindAssemblyLine(AssemblyLine, AssemblyHeader);
+
+        // [WHEN] Open Assembly Lines page and invoke Show Document for the blanket order line
+        AssemblyLines.OpenView();
+        AssemblyLines.Filter.SetFilter("Document Type", Format(AssemblyLine."Document Type"::"Blanket Order"));
+        AssemblyLines.Filter.SetFilter("Document No.", AssemblyHeader."No.");
+        AssemblyLines.First();
+        AssemblyLines."Show Document".Invoke();
+
+        // [THEN] Blanket Assembly Order page is opened (verified by BlanketAssemblyOrderPageHandler)
+        AssemblyLines.Close();
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Asm. Line Show Document");
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Asm. Line Show Document");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        SetupBlanketAssemblyOrderNos();
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Asm. Line Show Document");
+    end;
+
+    local procedure SetupBlanketAssemblyOrderNos()
+    var
+        AssemblySetup: Record "Assembly Setup";
+    begin
+        AssemblySetup.Get();
+        if AssemblySetup."Blanket Assembly Order Nos." = '' then begin
+            AssemblySetup.Validate("Blanket Assembly Order Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+            AssemblySetup.Modify(true);
+        end;
+    end;
+
+    local procedure CreateBlanketAssemblyOrder(var AssemblyHeader: Record "Assembly Header")
+    var
+        Item: Record Item;
+        ChildItem: Record Item;
+        AssemblyLine: Record "Assembly Line";
+    begin
+        LibraryInventory.CreateItem(Item);
+        Clear(AssemblyHeader);
+        AssemblyHeader."Document Type" := AssemblyHeader."Document Type"::"Blanket Order";
+        AssemblyHeader.Insert(true);
+        AssemblyHeader.Validate("Item No.", Item."No.");
+        AssemblyHeader.Validate("Due Date", WorkDate());
+        AssemblyHeader.Validate(Quantity, LibraryRandom.RandInt(10));
+        AssemblyHeader.Modify(true);
+
+        LibraryInventory.CreateItem(ChildItem);
+        LibraryAssembly.CreateAssemblyLine(
+            AssemblyHeader, AssemblyLine, AssemblyLine.Type::Item,
+            ChildItem."No.", '', LibraryRandom.RandInt(10), 1, '');
+    end;
+
+    local procedure FindAssemblyLine(var AssemblyLine: Record "Assembly Line"; AssemblyHeader: Record "Assembly Header")
+    begin
+        AssemblyLine.SetRange("Document Type", AssemblyHeader."Document Type");
+        AssemblyLine.SetRange("Document No.", AssemblyHeader."No.");
+        AssemblyLine.FindFirst();
+    end;
+
+    [PageHandler]
+    [Scope('OnPrem')]
+    procedure BlanketAssemblyOrderPageHandler(var BlanketAssemblyOrder: TestPage "Blanket Assembly Order")
+    begin
+        BlanketAssemblyOrder.Close();
+    end;
+}
"

