+    [Test]
+    [Scope('OnPrem')]
+    procedure VerifyDueDateInReminderFinChargeEntryAfterUpdateDueDateToEarlierDate()
+    var
+        Customer: Record Customer;
+        ReminderLevel: Record "Reminder Level";
+        ReminderFinChargeEntry: Record "Reminder/Fin. Charge Entry";
+        CustLedgerEntry: Record "Cust. Ledger Entry";
+        DueDate: Date;
+        DocumentDate: Date;
+        IssuedReminderNo: Code[20];
+        EarlierDueDate: Date;
+    begin
+        // [FEATURE] [AI test]
+        // [SCENARIO 461162] The Due Date in the Reminder/Fin. Charge Entry is updated when Due Date in Cust. Ledger Entry is changed to an earlier date
+        Initialize();
+
+        // [GIVEN] Customer "C" with Reminder Terms
+        CreateCustomer(Customer, '');
+        DueDate := CreateAndPostSalesInvoice(Customer."No.", '');
+        GetReminderLevel(ReminderLevel, Customer."Reminder Terms Code");
+        DocumentDate := CalcDate('<' + Format(LibraryRandom.RandInt(5)) + 'D>', CalcDate(ReminderLevel."Grace Period", DueDate));
+
+        // [GIVEN] Create and issue reminder for "C"
+        CreateReminder(Customer."No.", DocumentDate, false);
+        IssuedReminderNo := IssueReminder(DocumentDate);
+
+        // [GIVEN] Update Due Date in Cust. Ledger Entry to a later date
+        DueDate := DocumentDate + LibraryRandom.RandIntInRange(16, 17);
+        CustLedgerEntry.SetRange("Customer No.", Customer."No.");
+        CustLedgerEntry.FindLast();
+        CustLedgerEntry.Validate("Due Date", DueDate);
+        CustLedgerEntry.Modify(true);
+
+        // [WHEN] Update Due Date in Cust. Ledger Entry to an earlier date than Reminder Due Date
+        EarlierDueDate := DocumentDate - LibraryRandom.RandIntInRange(5, 10);
+        CustLedgerEntry.Validate("Due Date", EarlierDueDate);
+        CustLedgerEntry.Modify(true);
+
+        // [THEN] Reminder/Fin. Charge Entry Due Date equals the earlier Cust. Ledger Entry Due Date
+        ReminderFinChargeEntry.SetRange(Type, ReminderFinChargeEntry.Type::Reminder);
+        ReminderFinChargeEntry.SetRange("No.", IssuedReminderNo);
+        ReminderFinChargeEntry.FindFirst();
+        Assert.AreEqual(EarlierDueDate, ReminderFinChargeEntry."Due Date", ReminderDueDateErr);
+    end;
