+        ProdOrderCompCmtLine: Record "Prod. Order Comp. Cmt Line";
+        RequisitionLine: Record "Requisition Line";
+        Comment1: Text[80];
+        Comment2: Text[80];
+    begin
+        // [FEATURE] [AI test]
+        // [SCENARIO 565432] When same item is listed twice in Production BOM with different Position values and different comments, Carry Out Action from Planning Worksheet copies correct comments to each Prod. Order Component.
+        Initialize();
+
+        // [GIVEN] Unit of Measure "UOM" and Component Item "CI" with Purchase replenishment.
+        LibraryInventory.CreateUnitOfMeasureCode(UnitOfMeasure);
+        CreateItemWithReorderPolicy(CompItem, UnitOfMeasure, ItemUnitOfMeasure, CompItem."Replenishment System"::Purchase, CompItem."Reordering Policy"::" ");
+
+        // [GIVEN] Production Item "PI" with Prod. Order replenishment and Order reordering policy.
+        CreateItemWithReorderPolicy(ProdItem, UnitOfMeasure, ItemUnitOfMeasure, ProdItem."Replenishment System"::"Prod. Order", ProdItem."Reordering Policy"::Order);
+
+        // [GIVEN] Production BOM with first line for Item "CI" with Position "P1".
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ProdItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '',
+            ProductionBOMLine.Type::Item, CompItem."No.", LibraryRandom.RandInt(10));
+        ProductionBOMLine.Validate(Position, 'P1');
+        ProductionBOMLine.Modify(true);
+        ProductionBOMLine1 := ProductionBOMLine;
+
+        // [GIVEN] Second BOM line for the same Item "CI" with Position "P2".
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '',
+            ProductionBOMLine.Type::Item, CompItem."No.", LibraryRandom.RandInt(10));
+        ProductionBOMLine.Validate(Position, 'P2');
+        ProductionBOMLine.Modify(true);
+
+        // [GIVEN] Comment "C1" on first BOM line and Comment "C2" on second BOM line.
+        LibraryManufacturing.CreateProductionBOMCommentLine(ProductionBOMLine1);
