+        ProdOrderCompCmtLine.SetRange("Prod. Order BOM Line No.", ProdOrderComponent."Line No.");
+        ProdOrderCompCmtLine.FindFirst();
+        Assert.AreEqual(Comment2, ProdOrderCompCmtLine.Comment, 'Comment for Position P2 should match second BOM line comment.');
+    end;
