+    [Test]
+    procedure GetPrimaryContactReturnsContactViaBusinessRelationWhenNoPrimaryContact()
+    var
+        Customer: Record Customer;
+        Contact: Record Contact;
+        ContactBusinessRelation: Record "Contact Business Relation";
+        PrimaryContact: Record Contact;
+        Email: Text[80];
+    begin
+        // [FEATURE] [AI test]
+        // [SCENARIO 558926] GetPrimaryContact returns contact from business relation when customer has no primary contact
+        Initialize();
+
+        // [GIVEN] Customer "C" with no "Primary Contact No."
+        LibrarySales.CreateCustomer(Customer);
+        Customer."Primary Contact No." := '';
+        Customer.Modify();
+
+        // [GIVEN] Contact "CO" linked to "C" via business relation with email
+        ContactBusinessRelation.SetRange("Link to Table", ContactBusinessRelation."Link to Table"::Customer);
+        ContactBusinessRelation.SetRange("No.", Customer."No.");
+        ContactBusinessRelation.FindFirst();
+        Contact.Get(ContactBusinessRelation."Contact No.");
+        Email := 'test@test.de';
+        Contact."E-Mail" := Email;
+        Contact.Modify();
+
+        // [WHEN] GetPrimaryContact is called for customer "C"
+        Customer.GetPrimaryContact(Customer."No.", PrimaryContact);
+
+        // [THEN] Contact "CO" with email is returned
+        Assert.AreEqual(Contact."No.", PrimaryContact."No.", 'Primary contact should be found via business relation');
+        Assert.AreEqual(Email, PrimaryContact."E-Mail", 'Email should be populated from the contact');
+    end;
