+    [Test]
+    procedure ProdOrderCompQtyPerNotZeroWhenUOMQtyRoundPrecIsOne()
+    var
+        ComponentItem: Record Item;
+        FinishedGoodItem: Record Item;
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ProductionOrder: Record "Production Order";
+        ProdOrderComponent: Record "Prod. Order Component";
+        QuantityPer: Decimal;
+    begin
+        // [FEATURE] [AI test]
+        // [SCENARIO 537222] Prod. Order Component "Qty. Per" should not be zero when component Item UOM has Qty. Rounding Precision = 1
+        Initialize();
+
+        // [GIVEN] Component Item "C" with Rounding Precision = 0.01
+        LibraryInventory.CreateItem(ComponentItem);
+        ComponentItem.Validate("Rounding Precision", 0.01);
+        ComponentItem.Modify(true);
+
+        // [GIVEN] Component Item "C" Base UOM with Qty. Rounding Precision = 1
+        ItemUnitOfMeasure.Get(ComponentItem."No.", ComponentItem."Base Unit of Measure");
+        ItemUnitOfMeasure."Qty. Rounding Precision" := 1;
+        ItemUnitOfMeasure.Modify();
+
+        // [GIVEN] Certified Production BOM with Component "C" and Quantity Per = 0.09
+        QuantityPer := 0.09;
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ComponentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+          ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", QuantityPer);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        // [GIVEN] Finished Good Item "FG" with Replenishment System = Prod. Order and Production BOM
+        LibraryInventory.CreateItem(FinishedGoodItem);
+        FinishedGoodItem.Validate("Replenishment System", FinishedGoodItem."Replenishment System"::"Prod. Order");
+        FinishedGoodItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        FinishedGoodItem.Modify(true);
+
+        // [WHEN] Create and Refresh Released Production Order for "FG" with Quantity = 1
+        LibraryManufacturing.CreateProductionOrder(
+          ProductionOrder, ProductionOrder.Status::Released, ProductionOrder."Source Type"::Item, FinishedGoodItem."No.", 1);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, true, true, true, false);
+
+        // [THEN] Prod. Order Component "Quantity per" and "Expected Quantity" = 0.09
+        FindProdOrderComponent(ProdOrderComponent, ProductionOrder."No.", ComponentItem."No.");
+        Assert.AreEqual(QuantityPer, ProdOrderComponent."Quantity per", 'Quantity per should not be rounded to zero.');
+        Assert.AreEqual(QuantityPer, ProdOrderComponent."Expected Quantity", 'Expected Quantity should not be rounded to zero.');
+    end;
+
     local procedure Initialize()
     var
         LibraryERMCountryData: Codeunit "Library - ERM Country Data";
"

