+        Assert.AreEqual(ExpectedQty, ProdOrderComp."Expected Quantity", StrSubstNo(RelesedProdOrderComponentExpQtyRoundingErr, ProdOrderComp."Expected Quantity", ExpectedQty));
+    end;
