+    [Test]
+    procedure CopyJobTasksWithBeginEndTotalToMultipleCustomersBillingProject()
+    var
+        SourceJob: Record Job;
+        TargetJob: Record Job;
+        SourceJobTask: Record "Job Task";
+        TargetJobTask: Record "Job Task";
+        Customers: array[2] of Record Customer;
+        CopyJob: Codeunit "Copy Job";
+    begin
+        // [FEATURE] [AI test]
+        // [SCENARIO 507899] Copy Project Tasks with Begin-Total/End-Total task types to Project with Multiple Customers billing
+        Initialize();
+
+        // [GIVEN] Set Multiple Customers on Project Setup
+        SetMultiupleCustomersOnProjectSetup();
+
+        // [GIVEN] Create Customers "C1" and "C2"
+        LibrarySales.CreateCustomer(Customers[1]);
+        LibrarySales.CreateCustomer(Customers[2]);
+
+        // [GIVEN] Create source Project "P1" with Customer "C1" and One Customer billing
+        LibraryJob.CreateJob(SourceJob, Customers[1]."No.");
+        SourceJob.Validate("Task Billing Method", SourceJob."Task Billing Method"::"One customer");
+        SourceJob.Modify(true);
+
+        // [GIVEN] Create source Project Task with Begin-Total type
+        LibraryJob.CreateJobTask(SourceJob, SourceJobTask);
+        SourceJobTask.Validate("Job Task Type", SourceJobTask."Job Task Type"::"Begin-Total");
+        SourceJobTask.Modify(true);
+
+        // [GIVEN] Create target Project "P2" with Customer "C2" and Multiple Customers billing
+        LibraryJob.CreateJob(TargetJob, Customers[2]."No.");
+
+        // [WHEN] Copy Project Tasks from source to target
+        CopyJob.CopyJobTasks(SourceJob, TargetJob);
+
+        // [THEN] Begin-Total task is copied without error and has no customer data
+        TargetJobTask.Get(TargetJob."No.", SourceJobTask."Job Task No.");
+        Assert.AreEqual(TargetJobTask."Job Task Type"::"Begin-Total", TargetJobTask."Job Task Type", 'Job Task Type should be Begin-Total');
