+        ParentItem.Modify(true);
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ParentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ChildItem."No.", 5);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+        ParentItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ParentItem.Modify(true);
+        CalcStandardCost.CalcItem(ParentItem."No.", false);
+
+        // [GIVEN] BOM Cost tree for "P" generated when "C" has no Production BOM
+        CalculateTree(BOMBuffer, ParentItem);
+        BOMBuffer.SetRange(Type, BOMBuffer.Type::Item);
+        BOMBuffer.SetRange("No.", ChildItem."No.");
+        BOMBuffer.FindFirst();
+        RolledUpCapCostNoBOM := BOMBuffer."Rolled-up Capacity Cost";
+
+        // [WHEN] Assign blank certified Production BOM to "C" and regenerate cost tree for "P"
+        LibraryManufacturing.CreateProductionBOMHeader(BlankProdBOMHeader, ChildItem."Base Unit of Measure");
+        BlankProdBOMHeader.Validate(Status, BlankProdBOMHeader.Status::Certified);
+        BlankProdBOMHeader.Modify(true);
+        ChildItem.Validate("Production BOM No.", BlankProdBOMHeader."No.");
+        ChildItem.Modify(true);
+        BOMBuffer.Reset();
+        BOMBuffer.DeleteAll();
+        CalculateTree(BOMBuffer, ParentItem);
+
+        // [THEN] Rolled-up Capacity Cost for "C" is the same with blank Production BOM
+        BOMBuffer.SetRange(Type, BOMBuffer.Type::Item);
+        BOMBuffer.SetRange("No.", ChildItem."No.");
+        BOMBuffer.FindFirst();
+        RolledUpCapCostBlankBOM := BOMBuffer."Rolled-up Capacity Cost";
+        Assert.AreEqual(RolledUpCapCostNoBOM, RolledUpCapCostBlankBOM,
+            'Rolled-up Capacity Cost should be consistent for blank Production BOM vs no Production BOM');
+    end;
+
     local procedure Initialize()
     begin
         LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Kitting - Cost Shares Tree");
"

