+    [Test]
+    procedure VerifyMfgOverheadCostWithMultipleProdOrderLines()
+    var
+        RawItem: Record Item;
+        FGItem: Record Item;
+        ProductionOrder: Record "Production Order";
+        ProdOrderLine: Record "Prod. Order Line";
+        ProductionBOMHeader: Record "Production BOM Header";
+        MfgCostCalcMgt: Codeunit "Mfg. Cost Calculation Mgt.";
+        ExpMatCost: Decimal;
+        ExpCapDirCost: Decimal;
+        ExpSubDirCost: Decimal;
+        ExpCapOvhdCost: Decimal;
+        ExpMfgOvhdCost: Decimal;
+        ShareOfTotalCapCost: Decimal;
+        UnitCost: Decimal;
+        IndirectCostPct: Decimal;
+        LineQuantity: Decimal;
+    begin
+        // [FEATURE] [AI test]
+        // [SCENARIO 571596] Manufacturing overhead is correct when production order has multiple lines for the same item.
+        Initialize();
+
+        // [GIVEN] Raw material item "R" with Unit Cost = 100.
+        UnitCost := 100;
+        LibraryInventory.CreateItem(RawItem);
+        RawItem.Validate("Unit Cost", UnitCost);
+        RawItem.Modify(true);
+
+        // [GIVEN] Certified Production BOM with item "R", Quantity Per = 1.
+        CreateCertifiedProductionBOM(ProductionBOMHeader, RawItem, 1);
+
+        // [GIVEN] Finished good item "FG" with Indirect Cost % = 10 and Production BOM assigned.
+        IndirectCostPct := 10;
+        CreateProductionItem(FGItem, ProductionBOMHeader."No.");
+        FGItem.Validate("Indirect Cost %", IndirectCostPct);
+        FGItem.Modify(true);
+
+        // [GIVEN] Released production order with two lines for "FG", Quantity = 10 each.
+        LineQuantity := 10;
+        LibraryManufacturing.CreateProductionOrder(ProductionOrder, ProductionOrder.Status::Released, ProductionOrder."Source Type"::Item, '', 0);
+        LibraryManufacturing.CreateProdOrderLine(ProdOrderLine, ProductionOrder.Status, ProductionOrder."No.", FGItem."No.", '', '', LineQuantity);
+        LibraryManufacturing.CreateProdOrderLine(ProdOrderLine, ProductionOrder.Status, ProductionOrder."No.", FGItem."No.", '', '', LineQuantity);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, false, true, true, false);
+
+        // [WHEN] Calculate expected costs across all production order lines.
+        ProdOrderLine.SetRange(Status, ProductionOrder.Status);
+        ProdOrderLine.SetRange("Prod. Order No.", ProductionOrder."No.");
+        ProdOrderLine.FindSet();
+        repeat
+            MfgCostCalcMgt.CalcShareOfTotalCapCost(ProdOrderLine, ShareOfTotalCapCost);
+            MfgCostCalcMgt.CalcProdOrderLineExpCost(ProdOrderLine, ShareOfTotalCapCost, ExpMatCost, ExpCapDirCost, ExpSubDirCost, ExpCapOvhdCost, ExpMfgOvhdCost);
+        until ProdOrderLine.Next() = 0;
+
+        // [THEN] Material cost is 2000 (2 lines x 10 qty x 100 unit cost).
+        Assert.AreEqual(UnitCost * LineQuantity * 2, ExpMatCost, 'Expected material cost is incorrect.');
+
+        // [THEN] Manufacturing overhead is 10% of total material cost = 200.
+        Assert.AreEqual(Round(UnitCost * LineQuantity * 2 * IndirectCostPct / 100), ExpMfgOvhdCost, 'Manufacturing overhead cost is incorrect.');
+    end;
+
     local procedure Initialize()
     begin
         LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Production Orders IV");
"

