+        // [GIVEN] Finance Charge Terms "FCT" with Post Interest enabled
+        LibraryERM.CreateFinanceChargeTerms(FinanceChargeTerms);
+        Evaluate(VarDateFormula, '<1M>');
+        FinanceChargeTerms.Validate("Due Date Calculation", VarDateFormula);
+        FinanceChargeTerms.Validate("Interest Rate", LibraryRandom.RandIntInRange(1, 5));
+        FinanceChargeTerms.Validate("Interest Period (Days)", 30);
+        FinanceChargeTerms.Validate("Post Interest", true);
+        FinanceChargeTerms.Modify(true);
+
+        // [GIVEN] Customer "C" with "Allow Multiple Posting Groups" and Fin. Charge Terms "FCT"
+        LibrarySales.CreateCustomer(Customer);
+        Customer.Validate("Allow Multiple Posting Groups", true);
+        Customer.Validate("Fin. Charge Terms Code", FinanceChargeTerms.Code);
+        Customer.Modify(true);
+        CustomerPostingGroup.Get(Customer."Customer Posting Group");
+
+        // [GIVEN] Alternative Customer Posting Group "AltCPG" with different Receivables Account
+        LibrarySales.CreateCustomerPostingGroup(AltCustomerPostingGroup);
+        LibrarySales.CreateAltCustomerPostingGroup(CustomerPostingGroup.Code, AltCustomerPostingGroup.Code);
+
+        // [GIVEN] Finance Charge Memo for Customer "C" with Customer Posting Group set to "AltCPG"
+        LibraryERM.CreateFinanceChargeMemoHeader(FinanceChargeMemoHeader, Customer."No.");
+        FinanceChargeMemoHeader.Validate("Customer Posting Group", AltCustomerPostingGroup.Code);
+        FinanceChargeMemoHeader.Modify(true);
+        LibraryERM.CreateFinanceChargeMemoLine(FinanceChargeMemoLine, FinanceChargeMemoHeader."No.", FinanceChargeMemoLine.Type::"G/L Account");
+        FinanceChargeMemoLine.Validate("No.", AltCustomerPostingGroup."Interest Account");
+        FinanceChargeMemoLine.Validate(Amount, LibraryRandom.RandIntInRange(100, 1000));
+        FinanceChargeMemoLine.Modify(true);
+
+        // [WHEN] Issue Finance Charge Memo
+        LibraryERM.IssueFinanceChargeMemo(FinanceChargeMemoHeader);
+
+        // [THEN] G/L Entry is posted to Receivables Account of "AltCPG", not the original Customer Posting Group
+        IssuedFinChargeMemoHeader.SetRange("Customer No.", Customer."No.");
+        IssuedFinChargeMemoHeader.FindFirst();
+        GLEntry.SetRange("Document No.", IssuedFinChargeMemoHeader."No.");
+        GLEntry.SetRange("G/L Account No.", AltCustomerPostingGroup."Receivables Account");
+        Assert.AreEqual(1, GLEntry.Count(), 'G/L Entry should exist for alternative posting group Receivables Account');
+
+        // [THEN] No G/L Entry is posted to the original Customer Posting Group's Receivables Account
+        GLEntry.SetRange("G/L Account No.", CustomerPostingGroup."Receivables Account");
+        Assert.AreEqual(0, GLEntry.Count(), 'G/L Entry should not exist for original posting group Receivables Account');
+    end;
