@@ -0,0 +1,95 @@
+codeunit 134980 "Issued Reminder Email Tests"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+    EventSubscriberInstance = Manual;
+
+    var
+        Assert: Codeunit Assert;
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        ExpectedCustomerSystemId: Guid;
+        CustomerFoundAsRelatedEntity: Boolean;
+        IsInitialized: Boolean;
+
+    [Test]
+    procedure IssuedReminderEmailIncludesCustomerAsRelatedEntity()
+    var
+        IssuedReminderHeader: Record "Issued Reminder Header";
+        Customer: Record Customer;
+        ReportSelections: Record "Report Selections";
+        IssuedReminderEmailTests: Codeunit "Issued Reminder Email Tests";
+    begin
+        // [FEATURE] [AI test]
+        // [SCENARIO 123456] Issued reminder emails are logged in sent email history of a customer
+        Initialize();
+
+        // [GIVEN] Customer "C"
+        LibrarySales.CreateCustomer(Customer);
+
+        // [GIVEN] Issued Reminder "IR" for Customer "C"
+        CreateIssuedReminderHeader(IssuedReminderHeader, Customer);
+
+        // [WHEN] Send email for Issued Reminder "IR"
+        IssuedReminderEmailTests.SetExpectedCustomerSystemId(Customer.SystemId);
+        BindSubscription(IssuedReminderEmailTests);
+        ReportSelections.SendEmailInForeground(
+            IssuedReminderHeader.RecordId,
+            IssuedReminderHeader."No.",
+            'Reminder',
+            Enum::"Report Selection Usage"::Reminder.AsInteger(),
+            true,
+            Customer."No.");
+        UnbindSubscription(IssuedReminderEmailTests);
+
+        // [THEN] Customer "C" is included as related entity in email source records
+        Assert.IsTrue(
+            IssuedReminderEmailTests.GetCustomerFoundAsRelatedEntity(),
+            'Customer should be included as a related entity in email source records');
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Issued Reminder Email Tests");
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Issued Reminder Email Tests");
+        IsInitialized := true;
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Issued Reminder Email Tests");
+    end;
+
+    local procedure CreateIssuedReminderHeader(var IssuedReminderHeader: Record "Issued Reminder Header"; Customer: Record Customer)
+    begin
+        IssuedReminderHeader.Init();
+        IssuedReminderHeader."No." :=
+            LibraryUtility.GenerateRandomCode(IssuedReminderHeader.FieldNo("No."), Database::"Issued Reminder Header");
+        IssuedReminderHeader."Customer No." := Customer."No.";
+        IssuedReminderHeader."Customer Posting Group" := Customer."Customer Posting Group";
+        IssuedReminderHeader.Insert();
+    end;
+
+    procedure SetExpectedCustomerSystemId(NewSystemId: Guid)
+    begin
+        ExpectedCustomerSystemId := NewSystemId;
+    end;
+
+    procedure GetCustomerFoundAsRelatedEntity(): Boolean
+    begin
+        exit(CustomerFoundAsRelatedEntity);
+    end;
+
+    [EventSubscriber(ObjectType::Table, Database::"Report Selections", 'OnSendEmailDirectlyOnBeforeSend', '', false, false)]
+    local procedure HandleOnSendEmailDirectlyOnBeforeSend(var ReportSelections: Record "Report Selections"; ReportUsage: Enum "Report Selection Usage"; RecordVariant: Variant; var DocNo: Code[20]; var DocName: Text[150]; FoundBody: Boolean; FoundAttachment: Boolean; var EmailBody: Codeunit "Temp Blob"; var DefaultEmailAddress: Text[250]; ShowDialog: Boolean; var TempAttachReportSelections: Record "Report Selections" temporary; var CustomReportSelection: Record "Custom Report Selection"; var AllEmailsWereSuccessful: Boolean; var IsHandled: Boolean; var SourceTableIDs: List of [Integer]; var SourceIDs: List of [Guid]; var SourceRelationTypes: List of [Integer])
+    var
+        i: Integer;
+    begin
+        for i := 1 to SourceTableIDs.Count() do
+            if (SourceTableIDs.Get(i) = Database::Customer) and
+               (SourceIDs.Get(i) = ExpectedCustomerSystemId) and
+               (SourceRelationTypes.Get(i) = Enum::"Email Relation Type"::"Related Entity".AsInteger())
+            then
+                CustomerFoundAsRelatedEntity := true;
+        IsHandled := true;
+    end;
+}
"

