+    [Test]
+    procedure CarryOutActionMsgRespectsActionMessageFilterOnPlanningWorksheet()
+    var
+        Item: Record Item;
+        PurchaseHeader: Record "Purchase Header";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        RequisitionLine: Record "Requisition Line";
+        PurchaseOrderNo: Code[20];
+    begin
+        // [FEATURE] [AI test]
+        // [SCENARIO 575270] When filtering Planning Worksheet by Action Message and running Carry Out Action Message, only filtered lines are processed.
+        Initialize();
+
+        // [GIVEN] Item "I" with Reordering Policy = Order and Replenishment System = Purchase.
+        CreateItem(Item, Item."Reordering Policy"::Order, Item."Replenishment System"::Purchase);
+
+        // [GIVEN] Purchase Order "PO" for Item "I".
+        CreatePurchaseOrder(PurchaseHeader, Item."No.", WorkDate(), LibraryRandom.RandInt(10));
+        PurchaseOrderNo := PurchaseHeader."No.";
+
+        // [GIVEN] Sales Order "SO" for Item "I" with a future Shipment Date.
+        CreateSalesOrder(SalesHeader, SalesLine, Item."No.", LibraryRandom.RandInt(10));
+        UpdateShipmentDateOnSalesLine(SalesLine, CalcDate('<+1M>', WorkDate()));
+
+        // [GIVEN] Calculate Regenerative Plan producing Cancel and New action message lines.
+        Item.SetRange("No.", Item."No.");
+        LibraryPlanning.CalcRegenPlanForPlanWksh(Item, CalcDate('<-CM>', WorkDate()), CalcDate('<+2M>', WorkDate()));
+
+        // [GIVEN] Accept Action Message on all Requisition Lines for Item "I".
+        AcceptActionMessage(Item."No.");
+
+        // [WHEN] Set Action Message filter to Cancel and Carry Out Action Message.
+        SelectRequisitionLine(RequisitionLine, Item."No.");
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::Cancel);
+        LibraryPlanning.CarryOutActionMsgPlanWksh(RequisitionLine);
